const s='{% block sw_card_section %} <div class="sw-card-section" :class="cardSectionClasses" > <slot></slot> </div> {% endblock %}',t={template:s,props:{divider:{type:String,required:!1,default:"",validValues:["top","right","bottom","left"],validator(e){return e.length?["top","right","bottom","left"].includes(e):!0}},secondary:{type:Boolean,required:!1,default:!1},slim:{type:Boolean,required:!1,default:!1}},computed:{cardSectionClasses(){return{[`sw-card-section--divider-${this.divider}`]:this.divider,"sw-card-section--secondary":this.secondary,"sw-card-section--slim":this.slim}}}};export{t as default};
